const webhookData = $('Phase 3 — Webhook Trigger').first().json;
const items = $input.all();

// Get approved content_ids from the frontend request body
const approvedIds = webhookData.body?.content_ids || [];
const month = webhookData.body?.month || '';

const platformTimes = {
  'LinkedIn': { hour: 9, minute: 0 },
  'Instagram': { hour: 12, minute: 30 },
  'X': { hour: 15, minute: 0 },
  'YouTube': { hour: 14, minute: 0 },
  'Facebook': { hour: 10, minute: 0 },
  'TikTok': { hour: 19, minute: 0 }
};

const platformColors = {
  'LinkedIn': '9',
  'Instagram': '4',
  'X': '7',
  'YouTube': '11',
  'Facebook': '9',
  'TikTok': '2'
};

// Filter to only approved items if content_ids provided
let filteredItems = items;
if (approvedIds.length > 0) {
  filteredItems = items.filter(item => approvedIds.includes(item.json.id));
}

const output = filteredItems.map(item => {
  const d = item.json;
  const platform = d.platform || 'LinkedIn';
  const times = platformTimes[platform] || { hour: 9, minute: 0 };
  const dateStr = d.date || new Date().toISOString().split('T')[0];

  const startTime = `${dateStr}T${String(times.hour).padStart(2,'0')}:${String(times.minute).padStart(2,'0')}:00`;
  const endHour = times.hour + 1;
  const endTime = `${dateStr}T${String(endHour).padStart(2,'0')}:${String(times.minute).padStart(2,'0')}:00`;

  // Format summary to show the content title/theme
  const title = d.title || d.theme || d.content_type || 'Post';

  return {
    json: {
      summary: `[${platform}] ${title}`,
      description: `Theme: ${d.theme || ''}\nWeekly Show: ${d.weekly_show_name || ''}\n\nHook: ${d.hook || ''}\n\nContent Type: ${d.content_type || ''}\nPlatform: ${platform}\nAlso post on: ${d.secondary_platform || 'N/A'}\n\nCTA: ${d.cta || ''}\nHashtags: ${d.hashtags || ''}\n\nNotes: ${d.notes || ''}\n\n---\nGenerated by ELUXR Social Media Agent`,
      startTime: startTime,
      endTime: endTime,
      colorId: platformColors[platform] || '9',
      day_number: d.day_number,
      platform: platform,
      content_id: d.id
    }
  };
});

return output;

